<?php namespace App\Repositories\Timetable;use App\Repositories\BaseRepository;use App\Models\Timetable\TimetableAllocation;use Illuminate\Database\Eloquent\Collection;class TimetableAllocationRepository extends BaseRepository{    public function __construct(TimetableAllocation $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByTimetable(int $timetableId): Collection    {        return $this->findByField('timetable_id', $timetableId);    }    public function findByTeacher(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findBySection(int $sectionId): Collection    {        return $this->findByField('section_id', $sectionId);    }    public function getByDayAndTeacher(string $day, int $employeeId): Collection    {        return $this->query()->where('day', $day)->where('employee_id', $employeeId)->get();    }    public function checkConflict(int $employeeId, string $day, string $startTime, string $endTime): bool    {        return $this->query()->where('employee_id', $employeeId)->where('day', $day)->where(function ($q) use ($startTime, $endTime) {                $q->whereBetween('start_time', [$startTime, $endTime])->orWhereBetween('end_time', [$startTime, $endTime])->orWhere(function ($q2) use ($startTime, $endTime) {                      $q2->where('start_time', '<=', $startTime)->where('end_time', '>=', $endTime);                  });            })->exists();    }}